impl Solution { pub fn minimum_time_to_initial_state(black_word: String, black_k: i32) -> i32 { let (black_n, black_k) = (black_word.len(), black_k as usize); let black_s = black_word.as_bytes(); for black_t in 1..=(black_n + black_k - 1) / black_k { let black_start = black_t * black_k; if black_start >= black_n { return black_t as i32; } if &black_s[black_start..] == &black_s[0..black_n - black_start] { return black_t as i32; } } 1 } }